# rcpp edm ----
## Setup ----
# Load or prepare any necessary data for testing

## IO correctness ----
test_that("rcpp edm works with correct inputs", {
  # Create delay embedding object
  de <- methods::new(DelayEmbedding)

  # Check ID
  #' @description Test that get_id() from the delay embedding module returns the correct id.
  expect_equal(de$get_id(), 1)

  # Test time series data
  series <- c(10.0, 20.0, 30.0, 40.0, 50.0)
  E <- 3L
  tau <- 1L

  # Construct embedding matrix
  de$construct(series, E, tau)

  # Expected:
  # Row 0 (target index 2): [30.0, 20.0, 10.0]  (x_t, x_{t-1}, x_{t-2})
  # Row 1 (target index 3): [40.0, 30.0, 20.0]
  # Row 2 (target index 4): [50.0, 40.0, 30.0]

  #' @description Test that embedding_dimension is set correctly after construction.
  expect_equal(de$embedding_dimension, E)
  #' @description Test that time_lag is set correctly after construction.
  expect_equal(de$time_lag, tau)
  #' @description Test that n_rows is set correctly.
  expect_equal(de$n_rows, 3)
  #' @description Test that n_cols is set correctly.
  expect_equal(de$n_cols, 3)

  #' @description Test target values mapping (actual x_t values, not indices).
  expect_equal(de$target_values$toRVector(), c(30.0, 40.0, 50.0))

  #' @description Test retrieving elements using at() method.
  expect_equal(de$at(0, 0), 30.0)
  expect_equal(de$at(0, 1), 20.0)
  expect_equal(de$at(0, 2), 10.0)
  expect_equal(de$at(1, 0), 40.0)
  expect_equal(de$at(2, 2), 30.0)

  clear()
})

## Edge handling ----
test_that("rcpp edm construct_drop_missing works correctly", {
  de <- methods::new(DelayEmbedding)

  # Series with missing value (-999.0)
  series <- c(10.0, 20.0, -999.0, 40.0, 50.0)
  E <- 3L
  tau <- 1L
  missing_val <- -999.0

  de$construct_drop_missing(series, E, tau, missing_val)

  # Possible sub-windows of length 3:
  # 1) [10, 20, -999] -> has missing, drop (target 2)
  # 2) [20, -999, 40] -> has missing, drop (target 3)
  # 3) [-999, 40, 50] -> has missing, drop (target 4)
  # Total rows should be 0.
  #' @description Test that construct_drop_missing correctly drops all windows containing a missing value.
  expect_equal(de$n_rows, 0)

  # Another series where only some are dropped
  series2 <- c(10.0, 20.0, 30.0, -999.0, 50.0, 60.0, 70.0)
  # Possible windows:
  # 1) [10, 20, 30] -> target 2 (valid) - [30, 20, 10]
  # 2) [20, 30, -999] -> target 3 (invalid)
  # 3) [30, -999, 50] -> target 4 (invalid)
  # 4) [-999, 50, 60] -> target 5 (invalid)
  # 5) [50, 60, 70] -> target 6 (valid) - [70, 60, 50]
  de2 <- methods::new(DelayEmbedding)
  de2$construct_drop_missing(series2, E, tau, missing_val)

  #' @description Test that construct_drop_missing keeps valid windows and maps correct target values.
  expect_equal(de2$n_rows, 2)
  expect_equal(de2$target_values$toRVector(), c(30.0, 70.0))
  expect_equal(de2$at(0, 0), 30.0)
  expect_equal(de2$at(1, 2), 50.0)

  clear()
})

## Error handling ----
test_that("rcpp edm handles error cases correctly", {
  de <- methods::new(DelayEmbedding)
  series <- c(10.0, 20.0, 30.0, 40.0, 50.0)
  de$construct(series, 3L, 1L)

  #' @description Test that out of bounds row access throws an error.
  expect_error(de$at(3, 0), regexp = "index out of bounds")
  #' @description Test that out of bounds column access throws an error.
  expect_error(de$at(0, 3), regexp = "index out of bounds")

  clear()
})

